/// A chat message in a conversation.
#[frb(mirror(Message))]
pub enum Message {
    System {
        field0: SystemMessage,
    },
    User {
        field0: UserMessage,
    },
    Assistant {
        field0: AssistantMessage,
    },
    Tool {
        field0: ToolMessage,
    },
    Developer {
        field0: DeveloperMessage,
    },
    /// Deprecated legacy function-role message; retained for API compatibility.
    Function {
        field0: FunctionMessage,
    },
}

#[frb(mirror(UserContent))]
pub enum UserContent {
    Text { field0: String },
    Parts { field0: Vec<ContentPart> },
}

#[frb(mirror(ContentPart))]
pub enum ContentPart {
    Text { text: String },
    ImageUrl { image_url: ImageUrl },
    Document { document: DocumentContent },
    InputAudio { input_audio: AudioContent },
}

#[frb(mirror(ImageDetail))]
pub enum ImageDetail {
    Low,
    High,
    Auto,
}

/// The type discriminator for tool/tool-call objects.
///
/// Per the OpenAI spec this is always `"function"`. Using an enum enforces
/// that constraint at the type level and rejects any other value on
/// deserialization.
#[frb(mirror(ToolType))]
pub enum ToolType {
    Function,
}

#[frb(mirror(ToolChoice))]
pub enum ToolChoice {
    Mode { field0: ToolChoiceMode },
    Specific { field0: SpecificToolChoice },
}

#[frb(mirror(ToolChoiceMode))]
pub enum ToolChoiceMode {
    Auto,
    Required,
    None,
}

#[frb(mirror(ResponseFormat))]
pub enum ResponseFormat {
    Text,
    JsonObject,
    JsonSchema { json_schema: JsonSchemaFormat },
}

#[frb(mirror(StopSequence))]
pub enum StopSequence {
    Single { field0: String },
    Multiple { field0: Vec<String> },
}

/// Why a choice stopped generating tokens.
#[frb(mirror(FinishReason))]
pub enum FinishReason {
    Stop,
    Length,
    ToolCalls,
    ContentFilter,
    /// Deprecated legacy finish reason; retained for API compatibility.
    FunctionCall,
    /// Catch-all for unknown finish reasons returned by non-OpenAI providers.
    ///
    /// Note: this intentionally does **not** carry the original string (e.g.
    /// `Other(String)`).  Using `#[serde(other)]` requires a unit variant, and
    /// switching to `#[serde(untagged)]` would change deserialization semantics
    /// for all variants.  The original value can be recovered by inspecting the
    /// raw JSON if needed.
    Other,
}

/// Controls how much reasoning effort the model should use.
#[frb(mirror(ReasoningEffort))]
pub enum ReasoningEffort {
    Low,
    Medium,
    High,
}

/// The format in which the embedding vectors are returned.
#[frb(mirror(EmbeddingFormat))]
pub enum EmbeddingFormat {
    /// 32-bit floating-point numbers (default).
    Float,
    /// Base64-encoded string representation of the floats.
    Base64,
}

#[frb(mirror(EmbeddingInput))]
pub enum EmbeddingInput {
    Single { field0: String },
    Multiple { field0: Vec<String> },
}

/// Input to the moderation endpoint — a single string or multiple strings.
#[frb(mirror(ModerationInput))]
pub enum ModerationInput {
    Single { field0: String },
    Multiple { field0: Vec<String> },
}

/// A document to be reranked — either a plain string or an object with a text field.
#[frb(mirror(RerankDocument))]
pub enum RerankDocument {
    Text { field0: String },
    Object { text: String },
}

/// Document input for OCR — either a URL or inline base64 data.
#[frb(mirror(OcrDocument))]
pub enum OcrDocument {
    /// A publicly accessible document URL.
    Url {
        /// The document URL.
        url: String,
    },
    /// Inline base64-encoded document data.
    Base64 {
        /// Base64-encoded document content.
        data: String,
        /// MIME type (e.g. `"application/pdf"`, `"image/png"`).
        media_type: String,
    },
}

#[frb(mirror(FilePurpose))]
pub enum FilePurpose {
    Assistants,
    Batch,
    FineTune,
    Vision,
}

#[frb(mirror(BatchStatus))]
pub enum BatchStatus {
    Validating,
    Failed,
    InProgress,
    Finalizing,
    Completed,
    Expired,
    Cancelling,
    Cancelled,
}

/// How the API key is sent in the HTTP request.
#[frb(mirror(AuthHeaderFormat))]
pub enum AuthHeaderFormat {
    /// Bearer token: `Authorization: Bearer <key>`
    Bearer,
    /// Custom header: e.g., `X-Api-Key: <key>`
    ApiKey { field0: String },
    /// No authentication required.
    None,
}

/// How budget limits are enforced.
#[frb(mirror(Enforcement))]
pub enum Enforcement {
    /// Reject requests that would exceed the budget with
    /// [`LiterLlmError::BudgetExceeded`].
    Hard,
    /// Allow requests through but emit a `tracing::warn!` when the budget is
    /// exceeded.
    Soft,
}

/// Storage backend for the response cache.
#[frb(mirror(CacheBackend))]
pub enum CacheBackend {
    /// In-memory LRU cache (default). No external dependencies.
    Memory,
    /// OpenDAL-backed storage. Supports 40+ backends (S3, Redis, GCS, local FS, etc.).
    OpenDal {
        /// OpenDAL scheme name (e.g. "s3", "redis", "fs", "gcs", "azblob").
        scheme: String,
        /// Backend-specific configuration as key-value pairs passed to OpenDAL.
        config: std::collections::HashMap<String, String>,
    },
}

